package main

import (
	"net/http"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promhttp"
	"github.com/gorilla/mux"
	"log"
)

var (
	userRequests = prometheus.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user.",
		},
		[]string{"username"},
	)
)

func init() {
	prometheus.MustRegister(userRequests)
}

func recordUserRequest(w http.ResponseWriter, r *http.Request) {
	username := r.URL.Query().Get("username")
	if username == "" {
		http.Error(w, "username is required", http.StatusBadRequest)
		return
	}
	userRequests.WithLabelValues(username).Inc()
	w.WriteHeader(http.StatusOK)
	w.Write([]byte("Request recorded"))
}

func main() {
	r := mux.NewRouter()
	r.HandleFunc("/track", recordUserRequest).Methods("GET")
	r.Handle("/metrics", promhttp.Handler())

	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", r))
}